{"filePath": "/docs/security/oauth2.md", "content": "# OAuth 2.0 Implementation Guide

## Overview

We implement OAuth 2.0 authorization code flow with PKCE for secure third-party integrations.

## Flow Diagram

```
User → Your App → Authorization Server → User Grants → Callback → Token Exchange → Access Token
```

## Authorization Request

### Step 1: Generate PKCE Challenge

```javascript
const crypto = require('crypto');

function generatePKCE() {
  const verifier = crypto.randomBytes(32).toString('base64url');
  const challenge = crypto
    .createHash('sha256')
    .update(verifier)
    .digest('base64url');

  return { verifier, challenge };
}

const { verifier, challenge } = generatePKCE();

// Store verifier for token exchange
session.codeVerifier = verifier;
```

### Step 2: Redirect to Authorization

```javascript
const authUrl = new URL('https://auth.example.com/oauth/authorize');
authUrl.searchParams.set('client_id', process.env.OAUTH_CLIENT_ID);
authUrl.searchParams.set('redirect_uri', 'https://yourapp.com/callback');
authUrl.searchParams.set('response_type', 'code');
authUrl.searchParams.set('scope', 'read write');
authUrl.searchParams.set('state', crypto.randomBytes(16).toString('hex'));
authUrl.searchParams.set('code_challenge', challenge);
authUrl.searchParams.set('code_challenge_method', 'S256');

res.redirect(authUrl.toString());
```

## Token Exchange

### Step 3: Handle Callback

```javascript
app.get('/callback', async (req, res) => {
  const { code, state } = req.query;

  // Verify state to prevent CSRF
  if (state !== session.state) {
    return res.status(400).send('Invalid state');
  }

  // Exchange code for token
  const tokenResponse = await fetch('https://auth.example.com/oauth/token', {
    method: 'POST',
    headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
    body: new URLSearchParams({
      grant_type: 'authorization_code',
      code,
      redirect_uri: 'https://yourapp.com/callback',
      client_id: process.env.OAUTH_CLIENT_ID,
      code_verifier: session.codeVerifier
    })
  });

  const tokens = await tokenResponse.json();

  // Store tokens securely
  await storeTokens(req.user.id, tokens);

  res.redirect('/dashboard');
});
```

## Using Access Tokens

```javascript
async function callProtectedAPI(userId) {
  const tokens = await getStoredTokens(userId);

  const response = await fetch('https://api.example.com/v3/data', {
    headers: {
      'Authorization': `Bearer ${tokens.access_token}`
    }
  });

  if (response.status === 401) {
    // Token expired, refresh it
    const newTokens = await refreshAccessToken(tokens.refresh_token);
    await storeTokens(userId, newTokens);

    // Retry with new token
    return callProtectedAPI(userId);
  }

  return response.json();
}
```

## Token Refresh

```javascript
async function refreshAccessToken(refreshToken) {
  const response = await fetch('https://auth.example.com/oauth/token', {
    method: 'POST',
    headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
    body: new URLSearchParams({
      grant_type: 'refresh_token',
      refresh_token: refreshToken,
      client_id: process.env.OAUTH_CLIENT_ID
    })
  });

  return response.json();
}
```

## Token Storage

**Secure Storage:**

```javascript
const crypto = require('crypto');

function encryptToken(token) {
  const key = Buffer.from(process.env.ENCRYPTION_KEY, 'hex');
  const iv = crypto.randomBytes(16);
  const cipher = crypto.createCipheriv('aes-256-gcm', key, iv);

  let encrypted = cipher.update(token, 'utf8', 'hex');
  encrypted += cipher.final('hex');

  const authTag = cipher.getAuthTag();

  return {
    encrypted,
    iv: iv.toString('hex'),
    authTag: authTag.toString('hex')
  };
}

async function storeTokens(userId, tokens) {
  const encryptedAccess = encryptToken(tokens.access_token);
  const encryptedRefresh = encryptToken(tokens.refresh_token);

  await db.tokens.create({
    userId,
    accessToken: encryptedAccess,
    refreshToken: encryptedRefresh,
    expiresAt: new Date(Date.now() + tokens.expires_in * 1000)
  });
}
```

## Security Best Practices

1. **Always Use PKCE**
   - Protects against authorization code interception
   - Required for public clients (SPAs, mobile apps)

2. **Validate State Parameter**
   - Prevents CSRF attacks
   - Generate cryptographically random state

3. **Encrypt Stored Tokens**
   - Never store tokens in plain text
   - Use AES-256-GCM encryption

4. **Set Appropriate Scopes**
   - Request minimum necessary permissions
   - Document scope requirements

5. **Handle Token Expiration**
   - Implement automatic token refresh
   - Gracefully handle refresh failures

6. **Secure Redirect URIs**
   - Whitelist exact redirect URIs
   - Validate URI in callback

## Error Handling

```javascript
if (tokenResponse.error) {
  switch (tokenResponse.error) {
    case 'invalid_grant':
      // Code expired or already used
      logger.error('Authorization code invalid');
      return res.redirect('/login?error=auth_failed');

    case 'invalid_client':
      // Client credentials wrong
      logger.error('OAuth client misconfigured');
      return res.status(500).send('Configuration error');

    default:
      logger.error({ error: tokenResponse.error }, 'OAuth error');
      return res.redirect('/login?error=auth_failed');
  }
}
