{"filePath": "/docs/performance/redis-caching.md", "content": "# Redis Caching Strategy

## Overview

We use Redis for application-level caching to improve response times and reduce database load.

## Connection

```javascript
const Redis = require('ioredis');

const redis = new Redis({
  host: process.env.REDIS_HOST,
  port: process.env.REDIS_PORT || 6379,
  password: process.env.REDIS_PASSWORD,
  db: 0,
  retryStrategy: (times) => {
    return Math.min(times * 50, 2000);
  }
});
```

## Caching Patterns

### Cache-Aside (Lazy Loading)

```javascript
async function getUser(userId) {
  const cacheKey = `user:${userId}`;

  // Try cache first
  const cached = await redis.get(cacheKey);
  if (cached) {
    return JSON.parse(cached);
  }

  // Cache miss - fetch from database
  const user = await db.users.findById(userId);

  // Store in cache (1 hour TTL)
  await redis.setex(cacheKey, 3600, JSON.stringify(user));

  return user;
}
```

### Write-Through

```javascript
async function updateUser(userId, updates) {
  const user = await db.users.update(userId, updates);

  // Update cache immediately
  await redis.setex(
    `user:${userId}`,
    3600,
    JSON.stringify(user)
  );

  return user;
}
```

### Write-Behind (Write-Back)

```javascript
async function incrementPageView(pageId) {
  // Increment in cache
  await redis.incr(`pageviews:${pageId}`);

  // Batch write to DB every 5 minutes
  await redis.sadd('pageviews:dirty', pageId);
}

// Background job
setInterval(async () => {
  const dirtyPages = await redis.smembers('pageviews:dirty');

  for (const pageId of dirtyPages) {
    const views = await redis.get(`pageviews:${pageId}`);
    await db.pages.update(pageId, { views });
    await redis.srem('pageviews:dirty', pageId);
  }
}, 300000);
```

## Cache Invalidation

### Time-Based (TTL)

```javascript
// Short TTL for frequently changing data
await redis.setex('stock:AAPL', 60, price); // 1 minute

// Long TTL for static data
await redis.setex('config:app', 86400, config); // 24 hours
```

### Event-Based

```javascript
// Invalidate on update
async function updateUser(userId, updates) {
  await db.users.update(userId, updates);

  // Delete from cache
  await redis.del(`user:${userId}`);

  // Also invalidate related caches
  await redis.del(`user:${userId}:permissions`);
  await redis.del(`user:${userId}:preferences`);
}
```

### Pattern-Based

```javascript
// Delete all user-related keys
const keys = await redis.keys('user:123:*');
if (keys.length > 0) {
  await redis.del(...keys);
}

// Better: Use Redis SCAN to avoid blocking
let cursor = '0';
do {
  const [newCursor, keys] = await redis.scan(
    cursor,
    'MATCH', 'user:123:*',
    'COUNT', 100
  );
  if (keys.length > 0) {
    await redis.del(...keys);
  }
  cursor = newCursor;
} while (cursor !== '0');
```

## Advanced Patterns

### Cache Stampede Prevention

```javascript
const LOCK_TTL = 10; // seconds

async function getUserWithLock(userId) {
  const cacheKey = `user:${userId}`;
  const lockKey = `lock:${cacheKey}`;

  // Try cache
  const cached = await redis.get(cacheKey);
  if (cached) return JSON.parse(cached);

  // Try to acquire lock
  const acquired = await redis.set(
    lockKey,
    '1',
    'EX', LOCK_TTL,
    'NX'
  );

  if (acquired) {
    try {
      // We have the lock - fetch data
      const user = await db.users.findById(userId);
      await redis.setex(cacheKey, 3600, JSON.stringify(user));
      return user;
    } finally {
      await redis.del(lockKey);
    }
  } else {
    // Someone else is fetching - wait and retry
    await new Promise(r => setTimeout(r, 100));
    return getUserWithLock(userId);
  }
}
```

### Probabilistic Early Expiration

```javascript
function shouldRefresh(ttl, beta = 1) {
  const delta = Math.log(Math.random()) * beta * ttl;
  return delta < 0;
}

async function getWithPEE(key, ttl, fetchFn) {
  const cached = await redis.get(key);

  if (cached) {
    const remainingTTL = await redis.ttl(key);

    // Probabilistically refresh before expiration
    if (shouldRefresh(ttl - remainingTTL)) {
      // Refresh in background
      fetchFn().then(data => {
        redis.setex(key, ttl, JSON.stringify(data));
      });
    }

    return JSON.parse(cached);
  }

  const data = await fetchFn();
  await redis.setex(key, ttl, JSON.stringify(data));
  return data;
}
```

## Best Practices

1. **Use Appropriate TTLs**
   - User sessions: 1 hour
   - User profiles: 15 minutes
   - Product data: 5 minutes
   - Static config: 24 hours

2. **Namespace Your Keys**
   ```javascript
   user:123:profile
   user:123:permissions
   product:456:details
   session:abc:data
   ```

3. **Serialize Efficiently**
   - Use JSON for simple objects
   - Consider MessagePack for binary efficiency
   - Compress large values with gzip

4. **Monitor Cache Performance**
   ```javascript
   const hits = await redis.get('stats:cache:hits');
   const misses = await redis.get('stats:cache:misses');
   const hitRate = hits / (hits + misses);
   // Target: >80% hit rate
   ```

5. **Handle Cache Failures Gracefully**
   ```javascript
   async function getUser(userId) {
     try {
       const cached = await redis.get(`user:${userId}`);
       if (cached) return JSON.parse(cached);
     } catch (error) {
       // Redis down - continue without cache
       logger.warn('Cache unavailable:', error);
     }

     return db.users.findById(userId);
   }
   ```

6. **Use Pipelines for Multiple Operations**
   ```javascript
   const pipeline = redis.pipeline();
   pipeline.get('user:1');
   pipeline.get('user:2');
   pipeline.get('user:3');
   const results = await pipeline.exec();
   ```", "sessionId": "session_1731790800000_y3z4a5b6c", "workspaceId": "default"}

